INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('a8e62eca-282a-470f-b60b-8bb91788d5aa', 'promociones-electricos', 'hero', 'Vehículos 100% Eléctricos', 'Descubre nuestra gama completa de vehículos eléctricos con las mejores condiciones del mercado. Plan MOVES incluido y financiación a tu medida.', '{"badge": "Promociones Exclusivas", "stats": [{"label": "Ayudas Plan MOVES", "value": "7.000€"}, {"label": "Emisiones CO₂", "value": "0%"}, {"label": "Ahorro combustible", "value": "70%"}], "buttonPrimary": "Ver modelos", "buttonSecondary": "Solicitar información"}', 'https://readdy.ai/api/search-image?query=modern%20electric%20vehicle%20charging%20station%20at%20sunset&width=1440&height=810&seq=promo-electricos-hero-1&orientation=landscape&format=webp', true, 1);
INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('eed2b455-269d-41c7-bdc3-1bbe82a39f55', 'promociones-electricos', 'technology', 'Tecnología eléctrica avanzada', 'Los vehículos eléctricos representan la evolución más significativa en la historia del automóvil.', '{"items": [{"icon": "ri-battery-2-charge-line", "title": "Baterías de última generación", "description": "Tecnología de iones de litio con alta densidad energética, garantía de 8 años y capacidad de carga rápida hasta el 80% en 30 minutos."}, {"icon": "ri-flashlight-line", "title": "Motores eléctricos eficientes", "description": "Motores síncronos de imanes permanentes con eficiencia superior al 95%, par instantáneo y conducción silenciosa."}, {"icon": "ri-refresh-line", "title": "Frenado regenerativo", "description": "Sistema que recupera energía durante la frenada, aumentando la autonomía hasta un 20% en conducción urbana."}, {"icon": "ri-smartphone-line", "title": "Conectividad total", "description": "Control remoto desde tu smartphone: preclimatización, estado de carga, localización y actualizaciones OTA."}], "howItWorks": [{"step": 1, "title": "Almacenamiento de energía", "description": "La batería almacena electricidad que alimenta el motor eléctrico."}, {"step": 2, "title": "Conversión de energía", "description": "El inversor convierte la corriente continua en alterna para el motor."}, {"step": 3, "title": "Propulsión instantánea", "description": "El motor eléctrico genera par máximo desde el primer momento."}, {"step": 4, "title": "Recuperación de energía", "description": "Al frenar, el motor actúa como generador y recarga la batería."}]}', NULL, true, 2);
INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('0c40fe4f-3ac3-4079-8410-ac162737ba61', 'promociones-electricos', 'benefits', '¿Por qué elegir un eléctrico?', 'Los vehículos eléctricos ofrecen ventajas económicas, medioambientales y de conducción que los convierten en la mejor opción.', '{"items": [{"icon": "ri-leaf-line", "color": "bg-green-500", "title": "Cero emisiones", "description": "Sin emisiones de CO₂ ni contaminantes. Contribuye activamente a la mejora de la calidad del aire."}, {"icon": "ri-money-euro-circle-line", "color": "bg-blue-500", "title": "Ahorro económico", "description": "Hasta un 70% de ahorro en combustible y mantenimiento reducido sin cambios de aceite ni filtros."}, {"icon": "ri-shield-check-line", "color": "bg-purple-500", "title": "Etiqueta CERO", "description": "Acceso libre a zonas de bajas emisiones, descuentos en peajes y aparcamiento gratuito."}, {"icon": "ri-government-line", "color": "bg-[#ad023b]", "title": "Ayudas y subvenciones", "description": "Plan MOVES III con hasta 7.000€ de ayuda directa. Grupo Avisa gestiona todo el proceso."}, {"icon": "ri-volume-mute-line", "color": "bg-indigo-500", "title": "Conducción silenciosa", "description": "Experiencia de conducción premium sin ruido de motor, solo el sonido del viento."}, {"icon": "ri-speed-line", "color": "bg-orange-500", "title": "Rendimiento superior", "description": "Par instantáneo desde 0 rpm. Aceleración inmediata y respuesta excepcional."}], "comparison": [{"concept": "Coste por 100 km", "electric": "2-3€", "combustion": "10-15€"}, {"concept": "Mantenimiento anual", "electric": "200-400€", "combustion": "600-1.200€"}, {"concept": "Emisiones CO₂", "electric": "0 g/km", "combustion": "120-180 g/km"}, {"concept": "Impuesto circulación", "electric": "75% descuento", "combustion": "100%"}, {"concept": "Acceso ZBE", "electric": "Sin restricciones", "combustion": "Limitado"}]}', NULL, true, 3);
