INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('ecc04af4-359e-4649-8ec7-c03de5d4f147', 'promociones-hibridos', 'advantages', 'Ventajas del híbrido enchufable', 'La transición perfecta hacia la movilidad eléctrica completa.', '{"items": [{"icon": "ri-route-line", "title": "Sin ansiedad de autonomía", "description": "Motor de combustión como respaldo para viajes largos."}, {"icon": "ri-charging-pile-line", "title": "Carga en casa", "description": "Recarga nocturna en enchufe doméstico para el uso diario."}, {"icon": "ri-money-euro-circle-line", "title": "Ahorro real", "description": "Hasta 50% de ahorro en combustible en uso mixto."}]}', NULL, true, 2);
INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('538f82e8-9d8c-468d-b7bf-32c72afe3604', 'postventa', 'hero', 'Servicio Postventa Especializado', 'Talleres oficiales con técnicos certificados en vehículos eléctricos e híbridos. Tu tranquilidad es nuestra prioridad.', '{"buttonPrimary": "Reservar cita", "buttonSecondary": "955 034 600"}', 'https://readdy.ai/api/search-image?query=Professional%20automotive%20service%20center%20with%20modern%20electric%20vehicle&width=1440&height=600&seq=postventa-hero-1&orientation=landscape&format=webp', true, 1);
INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('8b3abc9e-d4ec-4db6-aacb-6fa46056bc47', 'postventa', 'services', 'Nuestros servicios', 'Ofrecemos un servicio integral para tu vehículo eléctrico o híbrido con los más altos estándares de calidad.', '{"items": [{"icon": "ri-tools-line", "title": "Mantenimiento especializado", "features": ["Revisiones oficiales con garantía del fabricante", "Diagnóstico de baterías y sistemas de carga", "Actualización de software y sistemas"], "description": "Técnicos certificados en alta tensión y sistemas eléctricos."}, {"icon": "ri-shield-check-line", "title": "Garantías extendidas", "features": ["Garantía de batería hasta 8 años o 160.000 km", "Cobertura de componentes eléctricos", "Asistencia en carretera 24/7"], "description": "Protección completa para tu inversión."}, {"icon": "ri-battery-charging-line", "title": "Asesoramiento en carga", "features": ["Instalación de wallbox en domicilio", "Gestión de ayudas para puntos de recarga", "Asesoramiento en tarifas eléctricas"], "description": "Te ayudamos a instalar tu punto de carga en casa o empresa."}, {"icon": "ri-car-line", "title": "Vehículo de sustitución", "features": ["Vehículos de sustitución eléctricos", "Recogida y entrega a domicilio", "Cita previa online 24/7"], "description": "Mantén tu movilidad mientras tu vehículo está en el taller."}, {"icon": "ri-file-list-3-line", "title": "Presupuestos sin compromiso", "features": ["Presupuesto previo obligatorio", "Sin sorpresas en la factura", "Piezas originales garantizadas"], "description": "Transparencia total en nuestros servicios."}, {"icon": "ri-time-line", "title": "Servicio express", "features": ["Cambio de aceite en 30 minutos", "Revisión pre-ITV express", "Cambio de neumáticos sin cita"], "description": "Intervenciones rápidas para que no pierdas tiempo."}]}', NULL, true, 2);
INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('9d0c5f90-1ebe-4610-9445-614cc550273f', 'postventa', 'plans', 'Planes de mantenimiento', 'Elige el plan que mejor se adapte a tus necesidades. Todos incluyen mano de obra y piezas originales.', '{"items": [{"name": "Revisión Básica", "price": "89", "features": ["Cambio de aceite y filtro", "Revisión de niveles", "Inspección visual de frenos", "Comprobación de luces", "Diagnóstico electrónico básico"], "description": "Mantenimiento esencial para tu vehículo", "highlighted": false}, {"name": "Revisión Completa", "price": "189", "features": ["Todo lo de Revisión Básica", "Cambio de filtro de aire", "Cambio de filtro de habitáculo", "Revisión de suspensión", "Diagnóstico de batería de alto voltaje", "Actualización de software"], "description": "Mantenimiento integral recomendado", "highlighted": true}, {"name": "Revisión Premium", "price": "289", "features": ["Todo lo de Revisión Completa", "Cambio de líquido de frenos", "Alineación y equilibrado", "Limpieza de inyectores", "Tratamiento antibacteriano A/C", "Lavado exterior e interior", "Vehículo de sustitución"], "description": "Servicio completo con extras", "highlighted": false}]}', NULL, true, 3);
INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('42d380c7-5264-4754-b31c-b75731870288', 'postventa', 'team', 'Técnicos especializados en movilidad eléctrica', 'Nuestro equipo cuenta con más de 50 técnicos certificados en vehículos eléctricos e híbridos.', '{"certifications": [{"icon": "ri-flashlight-line", "title": "Certificación Alta Tensión", "description": "Todos nuestros técnicos están certificados para trabajar con sistemas de alto voltaje."}, {"icon": "ri-award-line", "title": "Formación Continua", "description": "Actualización constante en las últimas tecnologías de Volkswagen, Audi y Škoda."}, {"icon": "ri-cpu-line", "title": "Equipamiento Oficial", "description": "Herramientas de diagnóstico oficiales y software actualizado de cada marca."}, {"icon": "ri-verified-badge-line", "title": "Garantía Oficial", "description": "Todas las intervenciones mantienen la garantía oficial del fabricante."}]}', NULL, true, 4);
