INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('7cd72f2d-6aa5-4d42-af1f-447389225f37', 'autoplus', 'requirements', 'Requisitos del Plan MOVES III', 'Condiciones para acceder a las ayudas del Gobierno para vehículos eléctricos.', '{"items": ["Vehículos nuevos 100% eléctricos o híbridos enchufables", "Autonomía eléctrica mínima de 30 km", "Precio máximo del vehículo: 45.000€ (turismos) / 53.000€ (furgonetas)", "Dar de baja un vehículo de más de 7 años para máxima ayuda", "Persona física o autónomo residente en España"]}', NULL, true, 2);
