INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('fad9312a-d544-4e01-a038-d22963ce4895', 'electrificacion', 'timeline', 'El camino hacia la electrificación', 'La evolución de la movilidad eléctrica desde sus inicios hasta el futuro.', '{"milestones": [{"year": "2020", "title": "Despegue del mercado EV", "description": "Las principales marcas lanzan sus primeros modelos 100% eléctricos de producción masiva."}, {"year": "2025", "title": "Paridad de costes", "description": "Los vehículos eléctricos alcanzan precios similares a los de combustión."}, {"year": "2030", "title": "Prohibición de nuevos ICE", "description": "Varios países europeos dejan de permitir la venta de coches nuevos de combustión."}, {"year": "2035", "title": "Solo eléctricos nuevos", "description": "La UE solo permite la venta de turismos de cero emisiones."}]}', NULL, true, 2);
INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('3b319730-60c2-45ce-97b5-182d8cfd9c74', 'electrificacion', 'infrastructure', 'Infraestructura de carga', 'España cuenta con una red creciente de puntos de carga públicos y privados.', '{"stats": [{"label": "Puntos de carga públicos en España", "value": "30.000+"}, {"label": "Cargadores rápidos (>50kW)", "value": "5.000+"}, {"label": "Nuevos puntos mensuales", "value": "500+"}]}', NULL, true, 3);
INSERT INTO public.sections (id, page_slug, section_key, title, subtitle, content, image_url, active, sort_order) VALUES ('9f6f87ef-f4e0-48df-a2ef-f2a1aa35b46a', 'conductores-adopcion', 'reasons', 'Razones para el cambio', 'Descubre por qué cada vez más conductores eligen vehículos eléctricos.', '{"items": [{"icon": "ri-money-euro-circle-line", "stats": "Ahorro medio: 1.500€/año", "title": "Ahorro real desde el primer día", "description": "Carga completa por menos de 10€. Sin cambios de aceite, filtros ni embrague. Mantenimiento un 50% más económico."}, {"icon": "ri-leaf-line", "stats": "0 g CO₂/km", "title": "Huella de carbono cero", "description": "Sin emisiones directas de CO₂. Si cargas con energía renovable, tu huella es prácticamente nula."}, {"icon": "ri-speed-line", "stats": "0-100 km/h desde 3.4s", "title": "Experiencia de conducción única", "description": "Par instantáneo, aceleración inmediata, conducción silenciosa y suave. Una vez pruebas un eléctrico, no quieres volver."}]}', NULL, true, 2);
