INSERT INTO public.testimonials (id, name, role, company, rating, content, image_url, published, sort_order) VALUES ('848e083c-fb87-4f9a-9bf1-6b23af859899', 'María García López', 'Clienta particular', 'Sevilla', 5, 'El proceso fue muy sencillo. El equipo de Grupo Avisa se encargó de toda la gestión y en menos de 3 meses ya tenía mi nuevo coche eléctrico con la ayuda aplicada. ¡Ahorro más de 150€ al mes en combustible!', 'https://readdy.ai/api/search-image?query=Professional%20Spanish%20woman%20in%20her%2040s%20smiling%20warmly%20portrait%20photo%20natural%20lighting%20clean%20white%20background%20friendly%20expression%20business%20casual%20attire&width=200&height=200&seq=test1&orientation=squarish&format=webp', true, 1);
INSERT INTO public.testimonials (id, name, role, company, rating, content, image_url, published, sort_order) VALUES ('37b34fd7-c5e6-42e2-9cd4-ef2a063bb959', 'Antonio Fernández Ruiz', 'Cliente particular', 'Málaga', 5, 'Tenía dudas sobre pasarme al eléctrico, pero con la ayuda del Plan MOVES y el asesoramiento de Grupo Avisa, fue la mejor decisión. La gestión de la subvención fue totalmente gratuita y muy rápida.', 'https://readdy.ai/api/search-image?query=Professional%20Spanish%20man%20in%20his%2050s%20smiling%20portrait%20photo%20natural%20lighting%20clean%20white%20background%20friendly%20expression%20casual%20smart%20attire&width=200&height=200&seq=test2&orientation=squarish&format=webp', true, 2);
INSERT INTO public.testimonials (id, name, role, company, rating, content, image_url, published, sort_order) VALUES ('928808ae-2edf-48f7-8548-c999a4bda755', 'Carmen Moreno Díaz', 'Autónoma', 'Córdoba', 5, 'Como autónoma, el Plan MOVES me permitió renovar mi vehículo de empresa con una ayuda significativa. El equipo me explicó todos los requisitos y se ocuparon de todo el papeleo.', 'https://readdy.ai/api/search-image?query=Professional%20Spanish%20woman%20in%20her%2030s%20smiling%20portrait%20photo%20natural%20lighting%20clean%20white%20background%20confident%20expression%20modern%20style&width=200&height=200&seq=test3&orientation=squarish&format=webp', true, 3);
INSERT INTO public.testimonials (id, name, role, company, rating, content, image_url, published, sort_order) VALUES ('b37d05a2-3861-4637-b150-f71187a89490', 'Francisco Jiménez Torres', 'Cliente particular', 'Huelva', 5, 'Achatarré mi antiguo diésel y conseguí la ayuda máxima de 7.000€. Además, con las ayudas regionales de Andalucía sumé otros 2.000€. El ahorro total fue increíble.', 'https://readdy.ai/api/search-image?query=Professional%20Spanish%20man%20in%20his%2040s%20smiling%20portrait%20photo%20natural%20lighting%20clean%20white%20background%20friendly%20approachable%20expression&width=200&height=200&seq=test4&orientation=squarish&format=webp', true, 4);
INSERT INTO public.testimonials (id, name, role, company, rating, content, image_url, published, sort_order) VALUES ('027deb4f-5f31-4779-bf2f-d0cf4d2eca80', 'Laura Sánchez Martín', 'Clienta particular', 'Sevilla', 5, 'Necesitaba un vehículo familiar grande y el ID.Buzz era perfecto. Gracias al Plan MOVES y la financiación especial, pude acceder a él. El equipo de Grupo Avisa fue excepcional.', 'https://readdy.ai/api/search-image?query=Professional%20Spanish%20woman%20in%20her%2045s%20smiling%20portrait%20photo%20natural%20lighting%20clean%20white%20background%20warm%20friendly%20expression&width=200&height=200&seq=test5&orientation=squarish&format=webp', true, 5);
INSERT INTO public.testimonials (id, name, role, company, rating, content, image_url, published, sort_order) VALUES ('5c8cd22b-2f8e-4a93-a143-57577de5d7f5', 'Pedro Romero Vega', 'Cliente particular', 'Cádiz', 5, 'Opté por un híbrido enchufable y recibí 5.000€ de ayuda. Perfecto para mis desplazamientos diarios en eléctrico y viajes largos sin preocupaciones. Muy contento con la gestión.', 'https://readdy.ai/api/search-image?query=Professional%20Spanish%20man%20in%20his%2035s%20smiling%20portrait%20photo%20natural%20lighting%20clean%20white%20background%20professional%20confident%20look&width=200&height=200&seq=test6&orientation=squarish&format=webp', true, 6);
